  "Trigonometría":          ["Ingeniería / Ciencias Exactas", "Matemática / Física"],
  "Física":                 ["Ingeniería / Ciencias Exactas", "Matemática / Física"],
  "Razonamiento Matemático":["Ingeniería / Ciencias Exactas", "Matemática / Física"],

  // Ciencias de la Salud / Biología
  "Química":                ["Ciencias de la Salud / Biología", "Biología / Química", "Ingeniería / Ciencias Exactas"],
  "Biología":               ["Ciencias de la Salud / Biología", "Biología / Química"],

  // Letras / Comunicación
  "Razonamiento Verbal":    ["Letras / Comunicación", "Lengua / Literatura"],
  "Lenguaje y Literatura":  ["Letras / Comunicación", "Lengua / Literatura"],

  // Ciencias Sociales / Humanidades
  "Historia y Geografía":   ["Ciencias Sociales / Humanidades", "Historia y Geografía"],
  "Historia del Perú":      ["Ciencias Sociales / Humanidades", "Historia y Geografía"]};

const Cursos = () => {
  const [cursos, setCursos] = useState([]);
  const [docentes, setDocentes] = useState([]);
  const [ciclos, setCiclos] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [modoEdicion, setModoEdicion] = useState(false);
  const [cursoActual, setCursoActual] = useState(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [filtroCiclo, setFiltroCiclo] = useState('');
  const [bloquesOcupados, setBloquesOcupados] = useState({}); // { bloque: "razon" }
  const [aulasOcupadasPorBloque, setAulasOcupadasPorBloque] = useState({}); // { bloque: ["Aula 1", ...] }
  const [totalAulasSede, setTotalAulasSede] = useState(20); // Valor por defecto
  const [formData, setFormData] = useState({
    nombre: '',
    descripcion: '',
    dias: '',
    horas: '',
    cupos_totales: 40,
    precio: '',
    fecha_inicio: '',
    fecha_fin: '',
    docente_id: '',
    seccion: '',
    aula: '',
    ciclo_id: ''
  });

  const opcionesDias = [
    // Días individuales (para cursos del sistema)
    'Lunes',
    'Martes',
    'Miércoles',
    'Jueves',
    'Viernes',
    'Sábado',
    'Domingo',
    // Combinaciones frecuentes
    'Lunes a Viernes',
    'Lunes, Miércoles y Viernes',
    'Martes y Jueves',
    'Sábados',
    'Sábados y Domingos'
  ];

  const opcionesHoras = [
    // Turno Mañana
    '7:00 AM - 9:00 AM',
    '9:00 AM - 11:00 AM',
    '11:30 AM - 1:30 PM',
    // Turno Tarde
    '2:00 PM - 4:00 PM',
    '4:00 PM - 6:00 PM',
    '6:00 PM - 7:00 PM'
  ];

  const opcionesAulas = [
    'Aula 1', 'Aula 2', 'Aula 3', 'Aula 4', 'Aula 5',
    'Aula 6', 'Aula 7', 'Aula 8',
    'Laboratorio 1', 'Laboratorio 2'
  ];

  useEffect(() => {
    cargarDatos();
  }, []);

  const cargarDatos = async () => {
    try {
      setLoading(true);
      const [cursosRes, docentesRes, ciclosRes] = await Promise.all([
        cursosAPI.getAll(),
        docentesAPI.getAll({ estado: 'activo' }),
        ciclosAPI.getAll()
      ]);
      setCursos(cursosRes.data.data);
      setDocentes(docentesRes.data.data);
      setCiclos(ciclosRes.data.data);
    } catch (error) {
      console.error('Error al cargar datos:', error);
      toast.error('Error al cargar datos');
    } finally {
      setLoading(false);
    }
  };

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    let newFormData = {
      ...formData,
      [name]: value
    };

    // Si se selecciona un aula, fijar cupos a 40
    if (name === 'aula' && value !== '') {
      newFormData.cupos_totales = 40;
    }

    // Sincronizar Turno automáticamente según las horas
    if (name === 'horas') {
      const manana = ["7:00 AM - 9:00 AM", "9:00 AM - 11:00 AM", "11:30 AM - 1:30 PM"];
      const tarde = ["2:00 PM - 4:00 PM", "4:00 PM - 6:00 PM", "6:00 PM - 7:00 PM"];

      if (manana.includes(value)) {
        newFormData.seccion = "Turno Mañana";
      } else if (tarde.includes(value)) {
        newFormData.seccion = "Turno Tarde";
      } else {
        newFormData.seccion = ""; // Resetear si se pone en vacío
      }
    }

    // Sincronizar Fechas automáticamente según el Ciclo
    if (name === 'ciclo_id') {
      const selectedCiclo = ciclos.find(c => c.id === parseInt(value));
      if (selectedCiclo) {
        newFormData.fecha_inicio = selectedCiclo.fecha_inicio ? selectedCiclo.fecha_inicio.split('T')[0] : '';
        newFormData.fecha_fin = selectedCiclo.fecha_fin ? selectedCiclo.fecha_fin.split('T')[0] : '';
      } else {
        newFormData.fecha_inicio = '';
        newFormData.fecha_fin = '';
      }
    }

    // Validar Especialidad del Docente
    if (name === 'docente_id' && value !== '') {
      const selectedDocente = docentes.find(d => d.id === parseInt(value));
      const cursoNombre = newFormData.nombre;

      if (selectedDocente && cursoNombre && SPECIALTY_MAP[cursoNombre]) {
        const requiredSpecialty = SPECIALTY_MAP[cursoNombre];
        const docenteSpecialty = selectedDocente.especialidad;

        const isCompatible = Array.isArray(requiredSpecialty) 
          ? requiredSpecialty.includes(docenteSpecialty)
          : requiredSpecialty === docenteSpecialty;

        if (!isCompatible) {
          toast.error(`¡Error de Especialidad! El docente ${selectedDocente.nombres} ${selectedDocente.apellidos} es especialista en "${docenteSpecialty}" y NO puede dictar "${cursoNombre}".`, {
            duration: 6000,
            icon: ''
          });
        }
      }
    }

    // Validar cuando cambia el nombre del curso
    if (name === 'nombre' && newFormData.docente_id !== '') {
      const selectedDocente = docentes.find(d => d.id === parseInt(newFormData.docente_id));
      if (selectedDocente && SPECIALTY_MAP[value]) {
        const requiredSpecialty = SPECIALTY_MAP[value];
        const docenteSpecialty = selectedDocente.especialidad;

        const isCompatible = Array.isArray(requiredSpecialty) 
          ? requiredSpecialty.includes(docenteSpecialty)
          : requiredSpecialty === docenteSpecialty;

        if (!isCompatible) {
          toast.error(`¡Error! Este docente no es especialista en "${value}" y no podrá ser asignado.`, { icon: '' });
        }
      }
    }

    setFormData(newFormData);
  };

  // Efecto para actualizar disponibilidad REAL-TIME
  useEffect(() => {
    if (showModal && formData.ciclo_id && formData.dias) {
        const params = {
          ciclo_id: formData.ciclo_id,
          dia: formData.dias};
        if (formData.docente_id) params.docente_id = formData.docente_id;
        if (formData.aula) params.aula = formData.aula;
        if (modoEdicion && cursoActual) params.curso_id_excluir = cursoActual.id;

        cursosAPI.getDisponibilidad(params)
          .then(res => {
            const { ocupados, totalAulasDisponibles } = res.data?.data || {};

            // Normalizar ocupación (Ahora es modelo 1:1 por bloque)
            const ocupadosNormalizados = {};
            if (ocupados) {
                Object.keys(ocupados).forEach(k => { 
                  // Normalizamos quitando espacios extra y a Mayúsculas
                  const normalizedKey = k.trim().toUpperCase();
                  ocupadosNormalizados[normalizedKey] = ocupados[k]; 
                });
            }
            setBloquesOcupados(ocupadosNormalizados);

            // Reseteamos aulas ocupadas ya que el modelo es 1:1
            setAulasOcupadasPorBloque({});
            if (totalAulasDisponibles) setTotalAulasSede(totalAulasDisponibles);
          })
          .catch(() => {
            setBloquesOcupados({});
            setAulasOcupadasPorBloque({});
          });
    } else {
        setBloquesOcupados({});
        setAulasOcupadasPorBloque({});
    }
  }, [showModal, formData.ciclo_id, formData.dias, formData.docente_id, modoEdicion, cursoActual]);

  const handleSubmit = async (e) => {
    e.preventDefault();

    try {
      // VALIDACIÓN ESTRICTA DE ESPECIALIDAD
      if (formData.docente_id) {
        const selectedDocente = docentes.find(d => d.id === parseInt(formData.docente_id));
        const cursoNombre = formData.nombre;

        if (selectedDocente && cursoNombre && SPECIALTY_MAP[cursoNombre]) {
          const requiredSpecialty = SPECIALTY_MAP[cursoNombre];
          const docenteSpecialty = selectedDocente.especialidad;

          const isCompatible = Array.isArray(requiredSpecialty)
            ? requiredSpecialty.includes(docenteSpecialty)
            : requiredSpecialty === docenteSpecialty;

          if (!isCompatible) {
            toast.error(`No se puede guardar: El docente seleccionado no es especialista en "${cursoNombre}".`, {
              icon: '',
              duration: 5000
            });
            return; // BLOQUEAR GUARDADO
          }
        }
      }

      // Validar fechas contra el ciclo seleccionado

      const horarioGenerado = formData.dias && formData.horas ? `${formData.dias} ${formData.horas}` : '';
      // En modo edición, si no se puede reconstruir el horario desde dias+horas, usar el horario original del curso
      const horarioFinal = horarioGenerado || (modoEdicion && cursoActual?.horario) || '';

      const data = {
        ...formData,
        nivel: 'Preuniversitario', // Hardcoded value since all are Preuniversitario
        horario: horarioFinal,
        cupos_totales: parseInt(formData.cupos_totales),
        precio: parseFloat(formData.precio),
        docente_id: formData.docente_id ? parseInt(formData.docente_id) : null,
        ciclo_id: formData.ciclo_id ? parseInt(formData.ciclo_id) : null
      };

      if (modoEdicion) {
        await cursosAPI.update(cursoActual.id, {
          ...data,
          cupos_disponibles: cursoActual.cupos_disponibles
        });
        toast.success('Curso actualizado exitosamente');
      } else {
        await cursosAPI.create(data);
        toast.success('Curso creado exitosamente');
      }
      cerrarModal();
      cargarDatos();
    } catch (error) {
      console.error('Error:', error);
      const msg = error.response?.data?.message || error.response?.data?.error || error.message || 'Error al guardar curso';
      toast.error(msg);
    }
  };

  const abrirModalNuevo = () => {
    setModoEdicion(false);
    setCursoActual(null);
    setFormData({
      nombre: '',
      descripcion: '',
      dias: '',
      horas: '',
      cupos_totales: 40,
      precio: '',
      fecha_inicio: '',
      fecha_fin: '',
      docente_id: '',
      seccion: '',
      aula: '',
      ciclo_id: ''
    });
    setShowModal(true);
  };

  const abrirModalEditar = (curso) => {
    setModoEdicion(true);
    setCursoActual(curso);

    // Intentar separar el horario actual en días y horas si coincide con nuestras opciones
    let currDias = '';
    let currHoras = '';
    if (curso.horario) {
      for (const d of opcionesDias) {
        if (curso.horario.includes(d)) {
          currDias = d;
          break;
        }
      }
      for (const h of opcionesHoras) {
        if (curso.horario.includes(h)) {
          currHoras = h;
          break;
        }
      }
      // Fallback si era un texto libre antiguamente
      if (!currDias && !currHoras) {
        currDias = curso.horario;
        // Si no hace match con opciones fijas, al menos conservar el texto en 'días' para no perderlo
      }
    }

    // Buscar fechas del ciclo si el curso no las tiene (para cursos creados masivamente)
    const selectedCiclo = ciclos.find(c => c.id === curso.ciclo_id);
    const cycleStart = selectedCiclo?.fecha_inicio ? selectedCiclo.fecha_inicio.split('T')[0] : '';
    const cycleEnd = selectedCiclo?.fecha_fin ? selectedCiclo.fecha_fin.split('T')[0] : '';

    setFormData({
      nombre: curso.nombre,
      descripcion: curso.descripcion || '',
      dias: currDias,
      horas: currHoras,
      cupos_totales: 40,
      precio: curso.precio,
      fecha_inicio: curso.fecha_inicio ? curso.fecha_inicio.split('T')[0] : cycleStart,
      fecha_fin: curso.fecha_fin ? curso.fecha_fin.split('T')[0] : cycleEnd,
      docente_id: curso.docente_id || '',
      seccion: curso.seccion || '',
      aula: curso.aula || '',
      ciclo_id: curso.ciclo_id || ''
    });
    setShowModal(true);
  };

  const duplicarCurso = (curso) => {
    setModoEdicion(false);
    setCursoActual(null);

    // Buscar fechas del ciclo
    const selectedCiclo = ciclos.find(c => c.id === curso.ciclo_id);
    const cycleStart = selectedCiclo?.fecha_inicio ? selectedCiclo.fecha_inicio.split('T')[0] : '';
    const cycleEnd = selectedCiclo?.fecha_fin ? selectedCiclo.fecha_fin.split('T')[0] : '';

    setFormData({
      nombre: curso.nombre,
      descripcion: curso.descripcion || '',
      dias: '',
      horas: '',
      cupos_totales: 40,
      precio: curso.precio,
      fecha_inicio: curso.fecha_inicio ? curso.fecha_inicio.split('T')[0] : cycleStart,
      fecha_fin: curso.fecha_fin ? curso.fecha_fin.split('T')[0] : cycleEnd,
      docente_id: '',
      seccion: '',
      aula: '',
      ciclo_id: curso.ciclo_id || ''
    });
    setShowModal(true);
  };

  const cerrarModal = () => {
    setShowModal(false);
    setModoEdicion(false);
    setCursoActual(null);
  };

  const eliminarCurso = async (id) => {
    if (window.confirm('¿Estás seguro de desactivar este curso?')) {
      try {
        await cursosAPI.delete(id);
        toast.success('Curso desactivado exitosamente');
        cargarDatos();
      } catch (error) {
        console.error('Error:', error);
        toast.error('Error al desactivar curso');
      }
    }
  };

  return (
    <div className="main-content">
      <Navbar title="Gestión de Cursos" />

      <div className="card">
        <div className="card-header">
          <h2 className="card-title">Lista de Cursos</h2>
          <button className="btn btn-primary" onClick={abrirModalNuevo}>
            <FaPlus /> Nuevo Curso
          </button>
        </div>

        {/* Buscador Premium de Cursos */}
        <div style={{
          padding: '0 24px 24px',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'space-between',
          gap: '20px',
          borderBottom: '1px solid #f1f5f9',
          marginBottom: '20px'
        }}>
          <div className="search-box" style={{ flex: 1, maxWidth: '400px', marginBottom: 0 }}>
            <FaSearch style={{ left: '14px', right: 'auto' }} />
            <input
              type="text"
              placeholder="Buscar curso por nombre, sección o docente..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="form-control"
              style={{ paddingLeft: '42px', borderRadius: '50px', backgroundColor: '#f8fafc' }}
            />
            {searchTerm && (
              <FaTimes
                onClick={() => setSearchTerm('')}
                style={{ cursor: 'pointer', color: '#ef4444' }}
              />
            )}
          </div>

          <div className="filter-group" style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
            <FaSync color="#64748b" />
            <select
              value={filtroCiclo}
              onChange={e => setFiltroCiclo(e.target.value)}
              className="form-control"
              style={{ padding: '6px 12px', fontSize: '13px', borderRadius: '8px', minWidth: '180px' }}
            >
              <option value="">Todos los Ciclos</option>
              {ciclos.map(c => (
                <option key={c.id} value={c.id}>
                  {c.nombre} ({c.fecha_inicio ? new Date(c.fecha_inicio).toLocaleDateString() : '-'} al {c.fecha_fin ? new Date(c.fecha_fin).toLocaleDateString() : '-'}) {c.estado === 'inactivo' ? '(Cerrado)' : ''}
                </option>
              ))}
            </select>
          </div>
          <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
            <span style={{
              width: '10px',
              height: '10px',
              borderRadius: '50%',
              backgroundColor: searchTerm ? '#4361ee' : '#cbd5e1'
            }}></span>
            <span style={{ fontSize: '13px', fontWeight: '500', color: '#64748b' }}>
              {searchTerm ? `Resultado: ${cursos.filter(curso => curso.estado !== 'inactivo').filter(curso => {
                const term = searchTerm.toLowerCase();
                const nombreDocente = curso.docente_nombres ? `${curso.docente_nombres} ${curso.docente_apellidos}`.toLowerCase() : '';
                return (
                  curso.nombre.toLowerCase().includes(term) ||
                  (curso.seccion && curso.seccion.toLowerCase().includes(term)) ||
                  nombreDocente.includes(term) ||
                  curso.codigo.toLowerCase().includes(term)
                );
              }).length} curso(s)` : `Mostrando ${cursos.filter(c => c.estado !== 'inactivo').length} curso(s) activos`}
            </span>
          </div>
        </div>

        {loading ? (
          <div className="loading"><div className="spinner"></div></div>
        ) : (
          <div className="table-container">
            <table>
              <thead>
                <tr>
                  <th>Código</th>
                  <th>Curso</th>
                  <th>Ciclo</th>
                  <th style={{ textAlign: 'center' }}>Aula</th>
                  <th>Docente</th>
                  <th>Horario</th>
                  <th style={{ textAlign: 'center' }}>Cupos</th>
                  <th>Precio</th>
                  <th>Inicio</th>
                  <th>Estado</th>
                  <th>Acciones</th>
                </tr>
              </thead>
              <tbody>
                {cursos.length === 0 ? (
                  <tr>
                    <td colSpan="11" style={{ textAlign: 'center', padding: '20px' }}>
                      No hay cursos registrados
                    </td>
                  </tr>
                ) : (
                  cursos.filter(curso => curso.estado !== 'inactivo').filter(curso => {
                    if (searchTerm === '' && filtroCiclo === '') return true;
                    const term = searchTerm.toLowerCase();
                    const nombreDocente = curso.docente_nombres ? `${curso.docente_nombres} ${curso.docente_apellidos}`.toLowerCase() : '';

                    const matchSearch = (
                      curso.nombre.toLowerCase().includes(term) ||
                      (curso.seccion && curso.seccion.toLowerCase().includes(term)) ||
                      nombreDocente.includes(term) ||
                      curso.codigo.toLowerCase().includes(term)
                    );

                    const matchCiclo = filtroCiclo ? curso.ciclo_id === parseInt(filtroCiclo) : true;

                    return matchSearch && matchCiclo;
                  }).map((curso) => {
                    const isVencido = curso.fecha_fin && new Date(curso.fecha_fin) < new Date(new Date().setHours(0, 0, 0, 0));
                    return (
                      <tr key={curso.id} style={{ opacity: isVencido ? 0.7 : 1 }}>
                        <td style={{ fontWeight: '700', color: 'var(--primary-color)', whiteSpace: 'nowrap' }}>
                          {curso.codigo}
                        </td>
                        <td>
                          <div style={{ fontWeight: '600' }}>{curso.nombre}</div>
                          <div style={{ fontSize: '0.85em', color: '#64748b' }}>{curso.seccion || 'Única'}</div>
                        </td>
                        <td style={{ fontSize: '0.9em', color: '#475569' }}>
                           {curso.ciclo_nombre || '-'}
                        </td>
                        <td style={{ textAlign: 'center' }}>
                           <span className={curso.aula ? 'badge badge-info' : 'badge badge-secondary'} style={{ background: curso.aula ? '#e0f2fe' : '#f1f5f9', color: curso.aula ? '#0369a1' : '#64748b', minWidth: '80px' }}>
                              {curso.aula || 'Sin aula'}
                           </span>
                        </td>
                        <td style={{ fontSize: '0.95em' }}>
                          {curso.docente_nombres ? `${curso.docente_nombres} ${curso.docente_apellidos}` : <em>Por asignar</em>}
                        </td>
                        <td style={{ whiteSpace: 'nowrap' }}>
                          <span className="badge badge-light" style={{ display: 'inline-flex', alignItems: 'center', gap: '4px', background: '#f8fafc', border: '1px solid #e2e8f0', padding: '2px 6px', fontSize: '11px' }}>
                            {curso.horario || '-'}
                          </span>
                        </td>
                        <td style={{ textAlign: 'center' }}>
                          <div style={{ 
                            fontSize: '14px', 
                            color: curso.cupos_disponibles === 0 ? '#ef4444' : '#1e293b',
                            background: '#f8fafc',
                            padding: '4px 8px',
                            borderRadius: '6px',
                            border: '1px solid #e2e8f0',
                            display: 'inline-block',
                            minWidth: '60px'
                          }}>
                            {curso.cupos_disponibles}/{curso.cupos_totales}
                          </div>
                        </td>
                        <td style={{ whiteSpace: 'nowrap' }}>S/ {parseFloat(curso.precio).toFixed(2)}</td>
                        <td>
                          {curso.fecha_inicio ? new Date(curso.fecha_inicio).toLocaleDateString() : '-'}
                          {curso.fecha_fin && (
                            <div style={{ fontSize: '0.8em', color: '#666' }}>
                              al {new Date(curso.fecha_fin).toLocaleDateString()}
                            </div>
                          )}
                        </td>
                        <td>
                          {isVencido ? (
                            <span className="badge badge-danger">Finalizado</span>
                          ) : (
                            <span className={`badge ${curso.estado === 'activo' ? 'badge-success' : 'badge-danger'}`}>
                              {curso.estado}
                            </span>
                          )}
                        </td>
                        <td>
                          <div style={{ display: 'flex', gap: '8px' }}>
                            <button
                              className="btn btn-small btn-warning"
                              onClick={() => abrirModalEditar(curso)}
                              title="Editar curso"
                            >
                              <FaEdit />
                            </button>
                            <button
                              className="btn btn-small btn-danger"
                              onClick={() => eliminarCurso(curso.id)}
                              title="Desactivar curso"
                            >
                              <FaTrash />
                            </button>
                            <button
                              className="btn btn-small btn-info"
                              onClick={() => duplicarCurso(curso)}
                              title="Duplicar curso (Crear nueva sección)"
                              style={{ backgroundColor: '#0ea5e9', color: 'white' }}
                            >
                              <FaCopy />
                            </button>
                          </div>
                        </td>
                      </tr>
                    );
                  })
                )}
              </tbody>
            </table>
          </div>
        )}
      </div>

      {/* Modal de formulario */}
      {showModal && (
        <div className="modal-overlay" onClick={cerrarModal}>
          <div className="modal" onClick={(e) => e.stopPropagation()}>
            <div className="modal-header">
              <h2 className="modal-title">
                {modoEdicion ? 'Editar Curso' : 'Nuevo Curso'}
              </h2>
              <button className="modal-close" onClick={cerrarModal}>×</button>
            </div>

            <form onSubmit={handleSubmit}>
              {/* BLOQUE 1: Identidad y Ciclo */}
              <div className="form-row">
                <div className="form-group">
                  <label>Nombre del Curso</label>
                  <select
                    name="nombre"
                    className="form-control"
                    value={formData.nombre}
                    onChange={handleInputChange}
                    required
                  >
                    <option value="">Seleccionar curso</option>
                    {CURSOS_PRESET.map((c, index) => (
                      <option key={index} value={c}>{c}</option>
                    ))}
                  </select>
                </div>

                <div className="form-group">
                  <label>Ciclo Académico</label>
                  <select
                    name="ciclo_id"
                    value={formData.ciclo_id}
                    onChange={handleInputChange}
                    required
                  >
                    <option value="">Seleccionar ciclo</option>
                    {ciclos.map(c => (
                      <option key={c.id} value={c.id}>
                        {c.nombre} {c.estado === 'inactivo' ? '(Cerrado)' : ''}
                      </option>
                    ))}
                  </select>
                </div>
              </div>

              {/* BLOQUE 2: Fechas del Ciclo */}
              <div className="form-row">
                <div className="form-group">
                  <label>Fecha de Inicio del Ciclo</label>
                  <input
                    type="date"
                    name="fecha_inicio"
                    value={formData.fecha_inicio}
                    readOnly
                    style={{ backgroundColor: '#f1f5f9', cursor: 'not-allowed' }}
                  />
                </div>

                <div className="form-group">
                  <label>Fecha de Fin del Ciclo</label>
                  <input
                    type="date"
                    name="fecha_fin"
                    value={formData.fecha_fin}
                    readOnly
                    style={{ backgroundColor: '#f1f5f9', cursor: 'not-allowed' }}
                  />
                </div>
              </div>

              {/* BLOQUE 3: Logística del Curso */}
              <div className="form-row">
                <div className="form-group">
                  <label>Docente Asignado</label>
                  <select
                    name="docente_id"
                    value={formData.docente_id}
                    onChange={handleInputChange}
                  >
                    <option value="">Sin asignar</option>
                    {docentes.map(d => (
                      <option key={d.id} value={d.id}>{d.nombres} {d.apellidos}</option>
                    ))}
                  </select>
                </div>

                <div className="form-group">
                  <label>Aula (Seleccionar Horario primero)</label>
                  <select
                    name="aula"
                    className="form-control"
                    value={formData.aula}
                    onChange={handleInputChange}
                  >
                    <option value="">Seleccionar Aula (Opcional)</option>
                    {opcionesAulas.map(aula => (
                      <option key={aula} value={aula}>
                        {aula}
                      </option>
                    ))}
                  </select>
                </div>
              </div>

              {/* BLOQUE 4: Programación y Horarios */}
              <div className="form-group">
                <label>Horario Fijo</label>
                <div style={{ display: 'flex', gap: '8px' }}>
                  <select
                    name="dias"
                    value={formData.dias}
                    onChange={handleInputChange}
                    style={{ flex: 1 }}
                    required
                  >
                    <option value="">Días</option>
                    {opcionesDias.map(d => <option key={d} value={d}>{d}</option>)}
                    {formData.dias && !opcionesDias.includes(formData.dias) && (
                      <option value={formData.dias}>{formData.dias} (Personalizado)</option>
                    )}
                  </select>

                  <select
                    name="horas"
                    value={formData.horas}
                    onChange={handleInputChange}
                    style={{ flex: 1 }}
                    required
                  >
                    <option value="">Bloque de Hora</option>
                    <optgroup label="Turno Mañana">
                      {["7:00 AM - 9:00 AM", "9:00 AM - 11:00 AM", "11:30 AM - 1:30 PM"].map(bloque => {
                        const razonOcupado = bloquesOcupados[bloque] || bloquesOcupados[bloque.trim().toUpperCase()];
                        const isDisabled = !!razonOcupado;

                        return (
                          <option key={bloque} value={bloque} disabled={isDisabled}>
                            {bloque} 
                            {razonOcupado ? ` (${razonOcupado})` : " (Disponible)"}
                          </option>
                        );
                      })}
                    </optgroup>
                    <optgroup label="Turno Tarde">
                      {["2:00 PM - 4:00 PM", "4:00 PM - 6:00 PM", "6:00 PM - 7:00 PM"].map(bloque => {
                        const razonOcupado = bloquesOcupados[bloque] || bloquesOcupados[bloque.trim().toUpperCase()];
                        const isDisabled = !!razonOcupado;

                        return (
                          <option key={bloque} value={bloque} disabled={isDisabled}>
                            {bloque} 
                            {razonOcupado ? ` (${razonOcupado})` : " (Disponible)"}
                          </option>
                        );
                      })}
                    </optgroup>
                  </select>
                </div>
                {formData.dias && (
                  <div style={{
                    marginTop: '12px',
                    padding: '10px 15px',
                    backgroundColor: '#eff6ff',
                    border: '1px solid #bfdbfe',
                    borderRadius: '10px',
                    fontSize: '13px',
                    color: '#1e40af',
                    display: 'flex',
                    alignItems: 'center',
                    gap: '10px',
                    animation: 'fadeIn 0.3s ease-in-out'
                  }}>
                    <FaCalendarCheck color="#3b82f6" size={16} />
                    <span>
                      <strong>Estado del {formData.dias}:</strong> 
                      {!formData.horas ? " Consulta el desplegable de horas para ver disponibilidad." : " Horario seleccionado correctamente."}
                    </span>
                  </div>
                )}
              </div>

              {/* BLOQUE 5: Detalles Finales (Turno, Cupos, Precio) */}
              <div className="form-row">
                <div className="form-group">
                  <label>Turno / Sección (Auto)</label>
                  <input
                    type="text"
                    name="seccion"
                    value={formData.seccion}
                    readOnly
                    placeholder="Auto-asignado por horario"
                    style={{ backgroundColor: '#f1f5f9', cursor: 'not-allowed', fontWeight: 'bold' }}
                  />
                </div>

                <div className="form-group">
                  <label>Cupos Totales (Auto)</label>
                  <input
                    type="number"
                    name="cupos_totales"
                    value={formData.cupos_totales}
                    onChange={handleInputChange}
                    readOnly
                    style={{ backgroundColor: '#f1f5f9', cursor: 'not-allowed', fontWeight: 'bold' }}
                    title="La capacidad está fijada en 40 estudiantes por aula según normativa."
                  />
                </div>

                <div className="form-group">
                  <label>Precio (S/)</label>
                  <input
                    type="number"
                    name="precio"
                    value={formData.precio}
                    onChange={handleInputChange}
                    step="0.01"
                    min="0"
                    required
                    style={{ fontWeight: 'bold', color: '#0f172a' }}
                  />
                </div>
              </div>

              {/* OPCIONAL: Descripción */}
              <div className="form-group">
                <label>Descripción / Observación (Opcional)</label>
                <textarea
                  name="descripcion"
                  value={formData.descripcion}
                  onChange={handleInputChange}
                  rows="2"
                  placeholder="Detalles adicionales sobre el curso..."
                />
              </div>

              <div style={{ display: 'flex', gap: '10px', justifyContent: 'flex-end', marginTop: '20px' }}>
                <button type="button" className="btn btn-outline" onClick={cerrarModal}>
                  Cancelar
                </button>
                <button type="submit" className="btn btn-primary">
                  {modoEdicion ? 'Actualizar' : 'Guardar'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Cursos;

// Página de Docentes - Gestión de Profesores
import React, { useState, useEffect } from 'react';
import Navbar from '../components/Navbar';
import { docentesAPI, estudiantesAPI } from '../services/api';
import { FaPlus, FaEdit, FaTrash, FaSearch, FaTimes } from 'react-icons/fa';
import toast from 'react-hot-toast';

const Docentes = () => {
    const [docentes, setDocentes] = useState([]);
    const [loading, setLoading] = useState(true);
    const [showModal, setShowModal] = useState(false);
    const [modoEdicion, setModoEdicion] = useState(false);
    const [docenteActual, setDocenteActual] = useState(null);
    const [searchTerm, setSearchTerm] = useState('');
    const [dniDuplicado, setDniDuplicado] = useState(false);

    const [formData, setFormData] = useState({
        nombres: '',
        apellidos: '',
        dni: '',
        telefono: '',
        email: '',
        especialidad: '',
        estado: 'activo'
    });

    useEffect(() => {
        cargarDocentes();
    }, []);

    // Effect for auto-generating email based on names and surnames
    useEffect(() => {
        if (!modoEdicion && (formData.nombres || formData.apellidos)) {
            const generarEmail = (nombres, apellidos) => {
                const primerNombre = nombres.trim().split(' ')[0].toLowerCase();

                // Handle case where apellidos might be empty
                let primerApellido = '';
                if (apellidos.trim()) {
                    primerApellido = apellidos.trim().split(' ')[0].toLowerCase();
                }

                // Remove accents
                const cleanNombre = primerNombre ? primerNombre.normalize("NFD").replace(/[\u0300-\u036f]/g, "") : '';
                const cleanApellido = primerApellido ? primerApellido.normalize("NFD").replace(/[\u0300-\u036f]/g, "") : '';

                if (cleanNombre && cleanApellido) {
                    return `${cleanNombre}.${cleanApellido}@academiaalba.com`;
                } else if (cleanNombre) {
                    return `${cleanNombre}@academiaalba.com`;
                }
                return '';
            };

            const nuevoEmail = generarEmail(formData.nombres, formData.apellidos);
            // Only update if it generates a complete email to avoid overwriting manually cleared fields immediately
            if (nuevoEmail !== formData.email) {
                setFormData(prev => ({ ...prev, email: nuevoEmail }));
            }
        }
    }, [formData.nombres, formData.apellidos, modoEdicion]);

    const cargarDocentes = async () => {
        try {
            setLoading(true);
            const response = await docentesAPI.getAll({ estado: 'activo' });
            setDocentes(response.data.data);
        } catch (error) {
            console.error('Error al cargar docentes:', error);
            toast.error('Error al cargar docentes');
        } finally {
            setLoading(false);
        }
    };

    const handleInputChange = async (e) => {
        const { name, value } = e.target;
        setFormData({ ...formData, [name]: value });

        // Verificar DNI duplicado en tiempo real (solo en modo creación)
        if (name === 'dni' && !modoEdicion && value.length === 8) {
            // Verificar contra docentes locales
            const existenteLocal = docentes.find(d => d.dni === value);
            if (existenteLocal) {
                setDniDuplicado(`¡DNI duplicado! Ya existe el docente: ${existenteLocal.nombres} ${existenteLocal.apellidos}`);
                toast.error(`¡DNI duplicado! Ya existe el docente: ${existenteLocal.nombres} ${existenteLocal.apellidos}`);
                return;
            }
            
            // Verificar contra la base de datos de estudiantes
            try {
                const response = await estudiantesAPI.getByDni(value);
                if (response.data && response.data.success) {
                    const est = response.data.data;
                    setDniDuplicado(`¡DNI duplicado! Ya existe el estudiante: ${est.nombres} ${est.apellidos}`);
                    toast.error(`¡DNI duplicado! Ya existe el estudiante: ${est.nombres} ${est.apellidos}`);
                }
            } catch (error) {
                // Si da 404, significa que NO existe en estudiantes, lo cual es correcto.
                // Si el error no es 404, de todos modos no asumimos duplicado, el backend lo atrapará
                if (error.response?.status === 404) {
                    setDniDuplicado(false);
                } else if (!dniDuplicado) {
                    setDniDuplicado(false);
                }
            }
        } else if (name === 'dni') {
            setDniDuplicado(false);
        }
    };

    const handleSubmit = async (e) => {
        e.preventDefault();

        if (dniDuplicado) {
            toast.error('No se puede guardar: el DNI ya está registrado.', { icon: '' });
            return;
        }

        try {
            if (modoEdicion) {
                await docentesAPI.update(docenteActual.id, formData);
                toast.success('Docente actualizado exitosamente');
            } else {
                await docentesAPI.create(formData);
                toast.success('Docente registrado exitosamente');
            }
            cerrarModal();
            cargarDocentes();
        } catch (error) {
            console.error('Error:', error);
            toast.error(error.response?.data?.message || 'Error al guardar docente');
        }
    };

    const abrirModalNuevo = () => {
        setModoEdicion(false);
        setDocenteActual(null);
        setDniDuplicado(false);
        setFormData({
            nombres: '',
            apellidos: '',
            dni: '',
            telefono: '',
            email: '',
            especialidad: '',
            estado: 'activo'
        });
        setShowModal(true);
    };

    const abrirModalEditar = (docente) => {
        setModoEdicion(true);
        setDocenteActual(docente);
        setFormData({
            nombres: docente.nombres,
            apellidos: docente.apellidos,
            dni: docente.dni,
            telefono: docente.telefono || '',
            email: docente.email,
            especialidad: docente.especialidad || '',
            estado: docente.estado || 'activo'
        });
        setShowModal(true);
    };

    const cerrarModal = () => {
        setShowModal(false);
        setModoEdicion(false);
        setDocenteActual(null);
        setDniDuplicado(false);
    };

    const eliminarDocente = async (id) => {
        if (window.confirm('¿Estás seguro de desactivar este docente?')) {
            try {
                await docentesAPI.delete(id);
                toast.success('Docente desactivado exitosamente');
                cargarDocentes();
            } catch (error) {
                console.error('Error:', error);
                toast.error(error.response?.data?.message || 'Error al desactivar docente');
            }
        }
    };

    return (
        <div className="main-content">
            <Navbar title="Gestión de Docentes" />

            <div className="card">
                <div className="card-header">
                    <h2 className="card-title">Lista de Docentes</h2>
                    <button className="btn btn-primary" onClick={abrirModalNuevo}>
                        <FaPlus /> Nuevo Docente
                    </button>
                </div>

                {/* Buscador Premium de Docentes */}
                <div style={{
                    padding: '0 24px 24px',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'space-between',
                    gap: '20px',
                    borderBottom: '1px solid #f1f5f9',
                    marginBottom: '20px'
                }}>
                    <div className="search-box" style={{ flex: 1, maxWidth: '400px', marginBottom: 0 }}>
                        <FaSearch style={{ left: '14px', right: 'auto' }} />
                        <input
                            type="text"
                            placeholder="Buscar docente por nombre o DNI..."
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                            className="form-control"
                            style={{ paddingLeft: '42px', borderRadius: '50px', backgroundColor: '#f8fafc' }}
                        />
                        {searchTerm && (
                            <FaTimes
                                onClick={() => setSearchTerm('')}
                                style={{ cursor: 'pointer', color: '#ef4444' }}
                            />
                        )}
                    </div>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                        <span style={{
                            width: '10px',
                            height: '10px',
                            borderRadius: '50%',
                            backgroundColor: searchTerm ? '#4361ee' : '#cbd5e1'
                        }}></span>
                        <span style={{ fontSize: '13px', fontWeight: '500', color: '#64748b' }}>
                            {searchTerm ? `Resultado: ${docentes.filter(docente => {
                                const term = searchTerm.toLowerCase();
                                return (
                                    docente.nombres.toLowerCase().includes(term) ||
                                    docente.apellidos.toLowerCase().includes(term) ||
                                    docente.dni.includes(term)
                                );
                            }).length} docente(s)` : `Total: ${docentes.length} docente(s) registrado(s)`}
                        </span>
                    </div>
                </div>

                {loading ? (
                    <div className="loading"><div className="spinner"></div></div>
                ) : (
                    <div className="table-container">
                        <table>
                            <thead>
                                <tr>
                                    <th>Código</th>
                                    <th>Apellidos y Nombres</th>
                                    <th>DNI</th>
                                    <th>Contacto</th>
                                    <th>Especialidad</th>
                                    <th>Estado</th>
                                    <th>Acciones</th>
                                </tr>
                            </thead>
                            <tbody>
                                {docentes.length === 0 ? (
                                    <tr>
                                        <td colSpan="7" style={{ textAlign: 'center', padding: '20px' }}>
                                            No hay docentes registrados
                                        </td>
                                    </tr>
                                ) : (
                                    docentes.filter(docente => {
                                        if (searchTerm === '') return true;
                                        const term = searchTerm.toLowerCase();
                                        return (
                                            docente.nombres.toLowerCase().includes(term) ||
                                            docente.apellidos.toLowerCase().includes(term) ||
                                            docente.dni.includes(term)
                                        );
                                    }).map((docente) => (
                                        <tr key={docente.id}>
                                            <td style={{ fontWeight: '700', color: 'var(--primary-color)' }}>
                                                {docente.codigo}
                                            </td>
                                            <td>
                                                <div style={{ fontWeight: '600' }}>{docente.apellidos}</div>
                                                <div style={{ fontSize: '0.9em', color: '#64748b' }}>{docente.nombres}</div>
                                            </td>
                                            <td>{docente.dni}</td>
                                            <td>
                                                <div style={{ fontSize: '0.9em' }}>{docente.email}</div>
                                                {docente.telefono && (
                                                    <div style={{ fontSize: '0.85em', color: '#64748b' }}>
                                                        {docente.telefono}
                                                    </div>
                                                )}
                                            </td>
                                            <td>{docente.especialidad || '-'}</td>
                                            <td>
                                                <span className={`badge ${docente.estado === 'activo' ? 'badge-success' : 'badge-danger'}`}>
                                                    {docente.estado}
                                                </span>
                                            </td>
                                            <td>
                                                <div style={{ display: 'flex', gap: '8px' }}>
                                                    <button
                                                        className="btn btn-small btn-warning"
                                                        onClick={() => abrirModalEditar(docente)}
                                                        title="Editar docente"
                                                    >
                                                        <FaEdit />
                                                    </button>
                                                    <button
                                                        className="btn btn-small btn-danger"
                                                        onClick={() => eliminarDocente(docente.id)}
                                                        title="Desactivar docente"
                                                    >
                                                        <FaTrash />
                                                    </button>
                                                </div>
                                            </td>
                                        </tr>
                                    ))
                                )}
                            </tbody>
                        </table>
                    </div>
                )}
            </div>

            {/* Modal de formulario */}
            {showModal && (
                <div className="modal-overlay" onClick={cerrarModal}>
                    <div className="modal" onClick={(e) => e.stopPropagation()}>
                        <div className="modal-header">
                            <h2 className="modal-title">
                                {modoEdicion ? 'Editar Docente' : 'Nuevo Docente'}
                            </h2>
                            <button className="modal-close" onClick={cerrarModal}>×</button>
                        </div>

                        <form onSubmit={handleSubmit}>
                            <div className="form-row">
                                <div className="form-group">
                                    <label>Nombres *</label>
                                    <input
                                        type="text"
                                        name="nombres"
                                        value={formData.nombres}
                                        onChange={handleInputChange}
                                        required
                                    />
                                </div>

                                <div className="form-group">
                                    <label>Apellidos *</label>
                                    <input
                                        type="text"
                                        name="apellidos"
                                        value={formData.apellidos}
                                        onChange={handleInputChange}
                                        required
                                    />
                                </div>
                            </div>

                            <div className="form-row">
                                <div className="form-group">
                                    <label>DNI *</label>
                                    <input
                                        type="text"
                                        name="dni"
                                        value={formData.dni}
                                        onChange={handleInputChange}
                                        maxLength="8"
                                        pattern="\d{8}"
                                        title="El DNI debe tener 8 dígitos"
                                        required
                                        style={dniDuplicado ? { borderColor: '#ef4444', backgroundColor: '#fef2f2' } : {}}
                                    />
                                    {dniDuplicado && (
                                        <div style={{ color: '#ef4444', fontSize: '12px', marginTop: '4px', fontWeight: '600' }}>
                                             {dniDuplicado}
                                        </div>
                                    )}
                                </div>

                                <div className="form-group">
                                    <label>Teléfono</label>
                                    <input
                                        type="text"
                                        name="telefono"
                                        value={formData.telefono}
                                        onChange={handleInputChange}
                                    />
                                </div>
                            </div>

                            <div className="form-row">
                                <div className="form-group">
                                    <label>Correo Electrónico (Auto-generado) *</label>
                                    <input
                                        type="email"
                                        name="email"
                                        value={formData.email}
                                        onChange={handleInputChange}
                                        required
                                        title="El correo se genera automáticamente a partir del nombre"
                                    />
                                </div>

                                <div className="form-group">
                                    <label>Especialidad *</label>
                                    <select
                                        name="especialidad"
                                        value={formData.especialidad}
                                        onChange={handleInputChange}
                                        required
                                        className="form-control"
                                    >
                                        <option value="">Seleccionar especialidad</option>
                                        <option value="Ingeniería / Ciencias Exactas">Ingeniería / Ciencias Exactas</option>
                                        <option value="Matemática / Física">Matemática / Física</option>
                                        <option value="Ciencias de la Salud / Biología">Ciencias de la Salud / Biología</option>
                                        <option value="Biología / Química">Biología / Química</option>
                                        <option value="Letras / Comunicación">Letras / Comunicación</option>
                                        <option value="Lengua / Literatura">Lengua / Literatura</option>
                                        <option value="Ciencias Sociales / Humanidades">Ciencias Sociales / Humanidades</option>
                                        <option value="Historia y Geografía">Historia y Geografía</option>
                                    </select>
                                </div>
                            </div>

                            {modoEdicion && (
                                <div className="form-row">
                                    <div className="form-group">
                                        <label>Estado</label>
                                        <select
                                            name="estado"
                                            value={formData.estado}
                                            onChange={handleInputChange}
                                        >
                                            <option value="activo">Activo</option>
                                            <option value="inactivo">Inactivo</option>
                                        </select>
                                    </div>
                                    <div className="form-group"></div>
                                </div>
                            )}

                            <div style={{ display: 'flex', gap: '10px', justifyContent: 'flex-end', marginTop: '20px' }}>
                                <button type="button" className="btn btn-outline" onClick={cerrarModal}>
                                    Cancelar
                                </button>
                                <button type="submit" className="btn btn-primary">
                                    {modoEdicion ? 'Actualizar' : 'Guardar'}
                                </button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
};

export default Docentes;

// Página de Pagos
import React, { useState, useEffect } from 'react';
import Navbar from '../components/Navbar';
import { pagosAPI, matriculasAPI } from '../services/api';
import { FaPlus, FaMoneyBillWave, FaFilePdf, FaSearch, FaTimes } from 'react-icons/fa';
import toast from 'react-hot-toast';
import jsPDF from 'jspdf';
import autoTable from 'jspdf-autotable';

const Pagos = () => {
  const [pagos, setPagos] = useState([]);
  const [matriculas, setMatriculas] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [filtroCodigo, setFiltroCodigo] = useState('');
  const [buscadorDni, setBuscadorDni] = useState('');
  const [matriculaSeleccionada, setMatriculaSeleccionada] = useState(null);
  const [formData, setFormData] = useState({
    matricula_id: '',
    monto: '',
    fecha_pago: new Date().toISOString().split('T')[0],
    metodo_pago: 'efectivo',
    numero_recibo: '',
    observaciones: ''
  });

  // Función para generar un número de recibo aleatorio basado en la fecha y hora
  const generarNumeroRecibo = () => {
    const ahora = new Date();
    const strFecha = ahora.getFullYear().toString() +
      (ahora.getMonth() + 1).toString().padStart(2, '0') +
      ahora.getDate().toString().padStart(2, '0');
    const strHora = ahora.getHours().toString().padStart(2, '0') +
      ahora.getMinutes().toString().padStart(2, '0') +
      ahora.getSeconds().toString().padStart(2, '0');
    return `REC-${strFecha}-${strHora}`;
  };

  useEffect(() => {
    cargarDatos();
  }, []);

  const cargarDatos = async () => {
    try {
      setLoading(true);
      const [resPagos, resMatriculas] = await Promise.all([
        pagosAPI.getAll(),
        matriculasAPI.getAll({ estado_matricula: 'activa' })
      ]);

      const matriculasConDeuda = resMatriculas.data.data.filter(
        m => m.estado_pago === 'pendiente' || m.estado_pago === 'parcial'
      );

      setPagos(resPagos.data.data);
      setMatriculas(matriculasConDeuda);
    } catch (error) {
      console.error('Error:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!formData.matricula_id || !matriculaSeleccionada) {
      toast.error('Debe seleccionar una matrícula válida con deuda pendiente.', { icon: '' });
      return;
    }

    if (parseFloat(formData.monto) <= 0) {
      toast.error('El monto debe ser mayor a 0.', { icon: '' });
      return;
    }

    try {
      await pagosAPI.create({
        ...formData,
        monto: parseFloat(formData.monto),
        usuario_registro: 'admin'
      });

      const alumno = matriculaSeleccionada
        ? `${matriculaSeleccionada.nombres} ${matriculaSeleccionada.apellidos}`
        : 'el estudiante';

      toast.success(`Pago de S/ ${parseFloat(formData.monto).toFixed(2)} registrado exitosamente para ${alumno}`);
      setShowModal(false);
      setMatriculaSeleccionada(null);
      setBuscadorDni('');
      setFormData({
        matricula_id: '',
        monto: '',
        fecha_pago: new Date().toISOString().split('T')[0],
        metodo_pago: 'efectivo',
        numero_recibo: '',
        observaciones: ''
      });
      cargarDatos();
    } catch (error) {
      toast.error(error.response?.data?.message || 'Error al registrar pago');
    }
  };

  const cerrarModal = () => {
    setShowModal(false);
    setMatriculaSeleccionada(null);
    setBuscadorDni('');
    setFormData({
      matricula_id: '',
      monto: '',
      fecha_pago: new Date().toISOString().split('T')[0],
      metodo_pago: 'efectivo',
      numero_recibo: '',
      observaciones: ''
    });
  };

  const handleMatriculaChange = (e) => {
    const id = e.target.value;
    const seleccionada = matriculas.find(m => m.id.toString() === id);
    setMatriculaSeleccionada(seleccionada || null);

    if (seleccionada) {
      const montoPendiente = (seleccionada.monto_total - seleccionada.monto_pagado).toFixed(2);
      setFormData({
        ...formData,
        matricula_id: id,
        monto: montoPendiente,
        numero_recibo: generarNumeroRecibo()
      });
    } else {
      setFormData({
        ...formData,
        matricula_id: id,
        monto: '',
        numero_recibo: ''
      });
    }
  };

  const exportarReciboPDF = (pago) => {
    // Orientación horizontal (landscape) o vertical (portrait)
    const doc = new jsPDF();

    // Colores corporativos (Azul Alba y Grises)
    const primaryColor = [30, 64, 175];   // Azul
    const secondaryColor = [243, 244, 246]; // Gris claro para fondos
    const textColor = [55, 65, 81];       // Gris oscuro para texto

    // 1. Cabecera (Fondo de color superior)
    doc.setFillColor(...primaryColor);
    doc.rect(0, 0, 210, 35, 'F'); // Ancho A4: 210, Altura cabecera: 35

    // Título Principal en Blanco
    doc.setTextColor(255, 255, 255);
    doc.setFont("helvetica", "bold");
    doc.setFontSize(28);
    doc.text("ACADEMIA ALBA", 105, 22, { align: "center" });

    // 2. Título Secundario - Comprobante
    doc.setTextColor(...primaryColor);
    doc.setFontSize(16);
    doc.text("COMPROBANTE DE PAGO", 105, 50, { align: "center" });

    // Línea separadora sutil
    doc.setDrawColor(200, 200, 200);
    doc.setLineWidth(0.5);
    doc.line(20, 56, 190, 56);

    // 3. Información Principal (Cajas lado a lado)
    const startY = 65;

    // Caja Izquierda: Detalle de Recibo
    doc.setFillColor(...secondaryColor);
    doc.roundedRect(20, startY, 80, 25, 3, 3, 'F');

    doc.setTextColor(...textColor);
    doc.setFontSize(10);
    doc.setFont("helvetica", "normal");
    doc.text("Número de Recibo:", 25, startY + 8);
    doc.text("Fecha Emisión:", 25, startY + 18);

    doc.setFont("helvetica", "bold");
    doc.text(pago.codigo || pago.numero_recibo || "Generado Auto.", 58, startY + 8);
    doc.text(new Date(pago.fecha_pago).toLocaleDateString(), 55, startY + 18);

    // Caja Derecha: Emisor (Academia)
    doc.roundedRect(110, startY, 80, 25, 3, 3, 'F');

    doc.setFont("helvetica", "normal");
    doc.text("RUC:", 115, startY + 8);
    doc.text("Dirección:", 115, startY + 18);

    doc.setFont("helvetica", "bold");
    doc.text("20123456789", 125, startY + 8);
    doc.text("Campus Central", 133, startY + 18);

    // 4. Datos del Estudiante
    const studentY = startY + 40;
    doc.setFont("helvetica", "bold");
    doc.setFontSize(12);
    doc.setTextColor(...primaryColor);
    doc.text("DATOS DEL ESTUDIANTE", 20, studentY);

    // Fila del estudiante
    doc.setFontSize(11);
    doc.setTextColor(...textColor);
    doc.setFont("helvetica", "bold");
    doc.text("Nombre:", 20, studentY + 8);
    doc.setFont("helvetica", "normal");
    doc.text(`${pago.nombres} ${pago.apellidos}`, 40, studentY + 8);

    doc.setFont("helvetica", "bold");
    doc.text("Curso:", 20, studentY + 16);
    doc.setFont("helvetica", "normal");
    doc.text(pago.curso_nombre || pago.curso || 'No especificado', 35, studentY + 16);

    // 5. Tabla de Detalles del Pago
    autoTable(doc, {
      startY: studentY + 25,
      head: [['Descripción del Concepto', 'Forma de Pago', 'Importe Neto']],
      body: [
        ['Abono a Matrícula Escolar', (pago.metodo_pago || 'efectivo').toUpperCase(), `S/ ${parseFloat(pago.monto).toFixed(2)}`]
      ],
      theme: 'grid',
      headStyles: {
        fillColor: primaryColor,
        textColor: 255,
        fontStyle: 'bold',
        halign: 'center',
        fontSize: 10
      },
      bodyStyles: {
        fontSize: 10,
        textColor: 50
      },
      columnStyles: {
        0: { halign: 'left', cellPadding: 5 },
        1: { halign: 'center', cellPadding: 5 },
        2: { halign: 'right', fontStyle: 'bold', cellPadding: 5 }
      },
      styles: {
        lineColor: [220, 220, 220],
        lineWidth: 0.1}
    });

    // 6. Sección de Totales
    const finalY = doc.lastAutoTable.finalY + 5; // Añadido un poco de espacio

    // Cuadro resumen de pago (ampliado hacia la izquierda)
    doc.setFillColor(...secondaryColor);
    doc.rect(120, finalY, 70, 20, 'F');
    // Línea de borde izquierda para el cuadro resumen
    doc.setDrawColor(...primaryColor);
    doc.setLineWidth(1);
    doc.line(120, finalY, 120, finalY + 20);

    doc.setFontSize(11); // Reducido un punto para evitar choque
    doc.setTextColor(...textColor);
    doc.setFont("helvetica", "bold");
    doc.text("TOTAL PAGADO", 125, finalY + 12);

    doc.setFontSize(13);
    doc.setTextColor(...primaryColor);
    doc.text(`S/ ${parseFloat(pago.monto).toFixed(2)}`, 185, finalY + 13, { align: "right" });

    // 7. Sello de la Academia (Texto legal)
    doc.setFontSize(8);
    doc.setTextColor(150, 150, 150);
    doc.setFont("helvetica", "italic");
    doc.text("Este recibo tiene validez oficial dentro de la institución.", 105, 270, { align: "center" });
    doc.text("Conserve este documento para cualquier aclaración futura.", 105, 275, { align: "center" });

    // 8. Generar PDF
    const safeName = `${pago.nombres}_${pago.apellidos}`.replace(/[^a-z0-9]/gi, '_').toLowerCase();
    doc.save(`Recibo_Alba_${pago.codigo || pago.numero_recibo}_${safeName}.pdf`);
  };

  return (
    <div className="main-content">
      <Navbar title="Gestión de Pagos" />

      <div className="card">
        <div className="card-header">
          <h2 className="card-title">Registro de Pagos</h2>
          <button className="btn btn-primary" onClick={() => setShowModal(true)}>
            <FaPlus /> Registrar Pago
          </button>
        </div>

        {/* Buscador Premium de Pagos */}
        <div style={{
          padding: '0 24px 24px',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'space-between',
          gap: '20px',
          borderBottom: '1px solid #f1f5f9',
          marginBottom: '20px'
        }}>
          <div className="search-box" style={{ flex: 1, maxWidth: '400px', marginBottom: 0 }}>
            <FaSearch style={{ left: '14px', right: 'auto' }} />
            <input
              type="text"
              placeholder="Buscar por código o recibo..."
              value={filtroCodigo}
              onChange={(e) => setFiltroCodigo(e.target.value)}
              className="form-control"
              style={{ paddingLeft: '42px', borderRadius: '50px', backgroundColor: '#f8fafc' }}
            />
            {filtroCodigo && (
              <FaTimes
                onClick={() => setFiltroCodigo('')}
                style={{ cursor: 'pointer', color: '#ef4444' }}
              />
            )}
          </div>
          <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
            <span style={{
              width: '10px',
              height: '10px',
              borderRadius: '50%',
              backgroundColor: filtroCodigo ? '#4361ee' : '#cbd5e1'
            }}></span>
            <span style={{ fontSize: '13px', fontWeight: '500', color: '#64748b' }}>
              {filtroCodigo ? `Resultado: ${pagos.filter(p =>
                (p.codigo && p.codigo.toLowerCase().includes(filtroCodigo.toLowerCase())) ||
                (p.numero_recibo && p.numero_recibo.toLowerCase().includes(filtroCodigo.toLowerCase()))
              ).length} pago(s)` : 'Todos los pagos registrados'}
            </span>
          </div>
        </div>

        {loading ? (
          <div className="loading"><div className="spinner"></div></div>
        ) : (
          <div className="table-container">
            <table>
              <thead>
                <tr>
                  <th>Código</th>
                  <th>Fecha</th>
                  <th>Estudiante</th>
                  <th>Curso</th>
                  <th>Monto</th>
                  <th>Método</th>
                  <th>Recibo Original</th>
                  <th>Acciones</th>
                </tr>
              </thead>
              <tbody>
                {pagos.length === 0 ? (
                  <tr>
                    <td colSpan="7" style={{ textAlign: 'center', padding: '20px' }}>
                      No hay pagos registrados
                    </td>
                  </tr>
                ) : (
                  pagos
                    .filter(pago =>
                      !filtroCodigo ||
                      (pago.codigo && pago.codigo.toLowerCase().includes(filtroCodigo.toLowerCase())) ||
                      (pago.numero_recibo && pago.numero_recibo.toLowerCase().includes(filtroCodigo.toLowerCase()))
                    )
                    .map((pago) => (
                      <tr key={pago.id}>
                        <td>{pago.codigo}</td>
                        <td>{new Date(pago.fecha_pago).toLocaleDateString()}</td>
                        <td>{pago.nombres} {pago.apellidos}</td>
                        <td>{pago.curso_nombre}</td>
                        <td>S/ {parseFloat(pago.monto).toFixed(2)}</td>
                        <td>
                          <span className="badge badge-info">{pago.metodo_pago}</span>
                        </td>
                        <td>{pago.numero_recibo || '-'}</td>
                        <td>
                          <button
                            className="btn btn-sm btn-secondary"
                            onClick={() => exportarReciboPDF(pago)}
                            title="Descargar Recibo en PDF"
                          >
                            <FaFilePdf color="#e63946" /> PDF
                          </button>
                        </td>
                      </tr>
                    ))
                )}
              </tbody>
            </table>
          </div>
        )}
      </div>

      {showModal && (
        <div className="modal-overlay" onClick={cerrarModal}>
          <div className="modal" onClick={(e) => e.stopPropagation()}>
            <div className="modal-header">
              <h2 className="modal-title">Registrar Pago</h2>
              <button className="modal-close" onClick={cerrarModal}>×</button>
            </div>

            <form onSubmit={handleSubmit}>
              {/* Buscador por DNI */}
              <div className="form-group">
                <label>Buscar por DNI del alumno</label>
                <input
                  type="text"
                  placeholder="Escribe el DNI para filtrar..."
                  value={buscadorDni}
                  onChange={(e) => {
                    const newValue = e.target.value;
                    setBuscadorDni(newValue);

                    // Siempre reiniciar la selección cuando el DNI cambia para evitar 
                    // que quede seleccionado un ID antiguo (fuga de estado)
                    if (formData.matricula_id) {
                      setMatriculaSeleccionada(null);
                      setFormData(prev => ({ ...prev, matricula_id: '', monto: '', numero_recibo: '' }));
                    }
                  }}
                  maxLength="8"
                />
              </div>

              <div className="form-group">
                <label>Matrícula</label>
                <select
                  value={formData.matricula_id}
                  onChange={handleMatriculaChange}
                  required
                >
                  <option value="">
                    {buscadorDni
                      ? matriculas.filter(m => m.dni && m.dni.includes(buscadorDni)).length === 0
                        ? 'Este alumno ya no tiene deudas pendientes'
                        : 'Seleccionar matrícula'
                      : 'Escribe el DNI arriba para filtrar'}
                  </option>
                  {matriculas
                    .filter(m => !buscadorDni || (m.dni && m.dni.includes(buscadorDni)))
                    .map(mat => (
                      <option key={mat.id} value={mat.id}>
                        {mat.dni} - {mat.nombres} {mat.apellidos} | {mat.curso_nombre}
                        {' '}(Pendiente: S/ {(mat.monto_total - mat.monto_pagado).toFixed(2)})
                      </option>
                    ))}
                </select>
              </div>

              {/* Recuadro de confirmación visual */}
              {matriculaSeleccionada && (
                <div style={{
                  backgroundColor: '#f8f9fa',
                  padding: '15px',
                  borderRadius: '8px',
                  marginBottom: '20px',
                  borderLeft: '4px solid #4361ee'
                }}>
                  <h4 style={{ margin: '0 0 10px 0', color: '#2b2d42' }}>Detalles del Estudiante</h4>
                  <p style={{ margin: '5px 0' }}><strong>Estudiante:</strong> {matriculaSeleccionada.nombres} {matriculaSeleccionada.apellidos}</p>
                  <p style={{ margin: '5px 0' }}><strong>Curso:</strong> {matriculaSeleccionada.curso_nombre}</p>
                  <p style={{ margin: '5px 0', color: '#e63946' }}><strong>Monto Pendiente:</strong> S/ {(matriculaSeleccionada.monto_total - matriculaSeleccionada.monto_pagado).toFixed(2)}</p>
                </div>
              )}

              <div className="form-row">
                <div className="form-group">
                  <label>Monto (S/)</label>
                  <input
                    type="number"
                    value={formData.monto}
                    onChange={(e) => {
                      const val = e.target.value;
                      if (matriculaSeleccionada) {
                        const max = (matriculaSeleccionada.monto_total - matriculaSeleccionada.monto_pagado);
                        if (val > max) {
                          setFormData({ ...formData, monto: max.toFixed(2) });
                        } else {
                          setFormData({ ...formData, monto: val });
                        }
                      } else {
                        setFormData({ ...formData, monto: val });
                      }
                    }}
                    step="0.01"
                    min="0"
                    required
                  />
                </div>

                <div className="form-group">
                  <label>Fecha de Pago</label>
                  <input
                    type="date"
                    value={formData.fecha_pago}
                    onChange={(e) => setFormData({ ...formData, fecha_pago: e.target.value })}
                    required
                  />
                </div>
              </div>

              <div className="form-row">
                <div className="form-group">
                  <label>Método de Pago</label>
                  <select
                    value={formData.metodo_pago}
                    onChange={(e) => setFormData({ ...formData, metodo_pago: e.target.value })}
                    required
                  >
                    <option value="efectivo">Efectivo</option>
                    <option value="transferencia">Transferencia</option>
                    <option value="tarjeta">Tarjeta</option>
                    <option value="yape">Yape</option>
                    <option value="plin">Plin</option>
                  </select>
                </div>

                <div className="form-group">
                  <label>Número de Recibo</label>
                  <input
                    type="text"
                    value={formData.numero_recibo}
                    onChange={(e) => setFormData({ ...formData, numero_recibo: e.target.value })}
                    readOnly
                    style={{ backgroundColor: '#e9ecef', cursor: 'not-allowed' }}
                  />
                </div>
              </div>

              <div className="form-group">
                <label>Observaciones</label>
                <textarea
                  value={formData.observaciones}
                  onChange={(e) => setFormData({ ...formData, observaciones: e.target.value })}
                  rows="3"
                />
              </div>

              <div style={{ display: 'flex', gap: '10px', justifyContent: 'flex-end', marginTop: '20px' }}>
                <button type="button" className="btn btn-outline" onClick={cerrarModal}>
                  Cancelar
                </button>
                <button type="submit" className="btn btn-primary">
                  Registrar Pago
                </button>
              </div>
            </form>
          </div>
        </div >
      )}
    </div >
  );
};

export default Pagos;

// Página de Reportes
import React, { useState, useEffect } from 'react';
import Navbar from '../components/Navbar';
import { reportesAPI } from '../services/api';
import { FaFileExport, FaExclamationTriangle } from 'react-icons/fa';
import toast from 'react-hot-toast';
import XLSX from 'xlsx-js-style';

const Reportes = () => {
  const [morosidad, setMorosidad] = useState(null);
  const [ingresos, setIngresos] = useState(null);
  const [loading, setLoading] = useState(true);
  const [fechaInicio, setFechaInicio] = useState('2026-01-01');
  const [fechaFin, setFechaFin] = useState(new Date().toISOString().split('T')[0]);

  useEffect(() => {
    cargarReportes();
  }, []);

  const cargarReportes = async () => {
    try {
      setLoading(true);
      const [resMorosidad, resIngresos] = await Promise.all([
        reportesAPI.getMorosidad({ fecha_inicio: fechaInicio, fecha_fin: fechaFin }),
        reportesAPI.getIngresos({ fecha_inicio: fechaInicio, fecha_fin: fechaFin })
      ]);
      setMorosidad(resMorosidad.data.data);
      setIngresos(resIngresos.data.data);
    } catch (error) {
      console.error('Error:', error);
    } finally {
      setLoading(false);
    }
  };

  const exportarExcelConsolidado = () => {
    // Verificar que haya datos en al menos uno de los dos
    const hayIngresos = ingresos && ingresos.pagos && ingresos.pagos.length > 0;
    const hayMorosidad = morosidad && morosidad.morosos && morosidad.morosos.length > 0;

    if (!hayIngresos && !hayMorosidad) {
      toast.error("No hay datos para exportar en este período.");
      return;
    }

    const wb = XLSX.utils.book_new();

    // =============================
    // HOJA 1: INGRESOS DETALLADOS
    // =============================
    if (hayIngresos) {
      const rowsIngresos = [];
      rowsIngresos.push([{
        v: "REPORTE OFICIAL DE INGRESOS - ACADEMIA ALBA",
        t: "s",
        s: {
          font: { name: "Arial", sz: 16, bold: true, color: { rgb: "FFFFFF" } },
          fill: { fgColor: { rgb: "1E40AF" } },
          alignment: { horizontal: "center", vertical: "center" }
        }
      }]);
      rowsIngresos.push([{
        v: `Período: ${fechaInicio} al ${fechaFin}`,
        t: "s",
        s: { font: { name: "Arial", sz: 12, italic: true }, alignment: { horizontal: "center" } }
      }]);
      rowsIngresos.push([{ v: "" }]);
      rowsIngresos.push([
        { v: `Total Ingresos: S/ ${ingresos.total || '0.00'}`, t: "s", s: { font: { bold: true, sz: 12, color: { rgb: "10B981" } } } },
        { v: `Cantidad de Pagos: ${ingresos.cantidad || 0}`, t: "s", s: { font: { bold: true, sz: 12 } } }
      ]);
      rowsIngresos.push([{ v: "" }]);

      const headersIngresos = ["Fecha", "Código de Recibo", "Nombres", "Apellidos", "Curso", "Monto (S/)", "Método de Pago"];
      rowsIngresos.push(headersIngresos.map(h => ({
        v: h, t: "s",
        s: {
          font: { bold: true, color: { rgb: "FFFFFF" } }, fill: { fgColor: { rgb: "3B82F6" } },
          alignment: { horizontal: "center", vertical: "center" },
          border: { top: { style: "thin", color: { auto: 1 } }, bottom: { style: "thin", color: { auto: 1 } }, left: { style: "thin", color: { auto: 1 } }, right: { style: "thin", color: { auto: 1 } } }
        }
      })));

      ingresos.pagos.forEach(pago => {
        rowsIngresos.push([
          { v: new Date(pago.fecha_pago).toLocaleDateString(), t: "s", s: { alignment: { horizontal: "center" } } },
          { v: pago.codigo, t: "s", s: { alignment: { horizontal: "center" } } },
          { v: pago.nombres, t: "s" },
          { v: pago.apellidos, t: "s" },
          { v: pago.curso, t: "s" },
          { v: parseFloat(pago.monto), t: "n", s: { numFmt: '"S/" #,##0.00', font: { bold: true } } },
          { v: pago.metodo_pago, t: "s", s: { alignment: { horizontal: "center" } } }
        ]);
      });

      const wsIngresos = XLSX.utils.aoa_to_sheet(rowsIngresos);
      wsIngresos["!merges"] = [
        { s: { r: 0, c: 0 }, e: { r: 0, c: 6 } },
        { s: { r: 1, c: 0 }, e: { r: 1, c: 6 } }
      ];
      // Aumentamos los anchos de columna para que el contenido no se corte
      wsIngresos['!cols'] = [
        { wch: 15 }, { wch: 25 }, { wch: 30 }, { wch: 30 }, { wch: 40 }, { wch: 20 }, { wch: 25 }
      ];
      XLSX.utils.book_append_sheet(wb, wsIngresos, "Ingresos");
    }

    // =============================
    // HOJA 2: DEUDAS PENDIENTES
    // =============================
    if (hayMorosidad) {
      const rowsDeudas = [];
      rowsDeudas.push([{
        v: "REPORTE DE MOROSIDAD Y DEUDAS PENDIENTES - ACADEMIA ALBA",
        t: "s",
        s: {
          font: { name: "Arial", sz: 16, bold: true, color: { rgb: "FFFFFF" } },
          fill: { fgColor: { rgb: "B45309" } },
          alignment: { horizontal: "center", vertical: "center" }
        }
      }]);
      rowsDeudas.push([{
        v: `Matrículas del Período: ${fechaInicio} al ${fechaFin}`,
        t: "s",
        s: { font: { name: "Arial", sz: 12, italic: true }, alignment: { horizontal: "center" } }
      }]);
      rowsDeudas.push([{ v: "" }]);
      rowsDeudas.push([
        { v: `Deuda Total Acumulada: S/ ${morosidad.totalDeuda || '0.00'}`, t: "s", s: { font: { bold: true, sz: 12, color: { rgb: "EF4444" } } } },
        { v: `Total de Morosos: ${morosidad.totalMorosos || 0}`, t: "s", s: { font: { bold: true, sz: 12 } } }
      ]);
      rowsDeudas.push([{ v: "" }]);

      const headersDeudas = ["DNI", "Estudiante", "Curso", "Teléfono", "Monto Total", "Pagado", "Deuda Pendiente", "Fecha Matrícula"];
      rowsDeudas.push(headersDeudas.map(h => ({
        v: h, t: "s",
        s: {
          font: { bold: true, color: { rgb: "FFFFFF" } }, fill: { fgColor: { rgb: "F59E0B" } },
          alignment: { horizontal: "center", vertical: "center" },
          border: { top: { style: "thin", color: { auto: 1 } }, bottom: { style: "thin", color: { auto: 1 } }, left: { style: "thin", color: { auto: 1 } }, right: { style: "thin", color: { auto: 1 } } }
        }
      })));

      morosidad.morosos.forEach(m => {
        rowsDeudas.push([
          { v: m.dni, t: "s", s: { alignment: { horizontal: "center" } } },
          { v: `${m.nombres} ${m.apellidos}`, t: "s" },
          { v: m.curso, t: "s" },
          { v: m.telefono || m.telefono_apoderado || '-', t: "s" },
          { v: parseFloat(m.monto_total), t: "n", s: { numFmt: '"S/" #,##0.00' } },
          { v: parseFloat(m.monto_pagado), t: "n", s: { numFmt: '"S/" #,##0.00' } },
          { v: parseFloat(m.monto_pendiente), t: "n", s: { numFmt: '"S/" #,##0.00', font: { bold: true, color: { rgb: "EF4444" } } } },
          { v: new Date(m.fecha_matricula).toLocaleDateString(), t: "s", s: { alignment: { horizontal: "center" } } }
        ]);
      });

      const wsDeudas = XLSX.utils.aoa_to_sheet(rowsDeudas);
      wsDeudas["!merges"] = [
        { s: { r: 0, c: 0 }, e: { r: 0, c: 7 } },
        { s: { r: 1, c: 0 }, e: { r: 1, c: 7 } }
      ];
      // Aumentamos los anchos de columna
      wsDeudas['!cols'] = [
        { wch: 15 }, { wch: 40 }, { wch: 40 }, { wch: 20 }, { wch: 20 }, { wch: 20 }, { wch: 25 }, { wch: 20 }
      ];
      XLSX.utils.book_append_sheet(wb, wsDeudas, "Morosidad");
    }

    XLSX.writeFile(wb, `Reporte_Consolidado_Alba_${fechaInicio}_a_${fechaFin}.xlsx`);
  };


  return (
    <div className="main-content">
      <Navbar title="Reportes y Estadísticas" />

      {/* Reporte de Ingresos */}
      <div className="card">
        <div className="card-header">
          <h2 className="card-title">Reporte de Ingresos</h2>
          <button
            className="btn btn-secondary"
            onClick={exportarExcelConsolidado}
            style={{ backgroundColor: '#10b981', color: 'white', borderColor: '#059669', fontSize: '1.05rem', padding: '10px 20px' }}
          >
            <FaFileExport /> Descargar Reporte (Excel)
          </button>
        </div>

        <div className="form-row" style={{ marginBottom: '20px' }}>
          <div className="form-group">
            <label>Fecha Inicio</label>
            <input
              type="date"
              value={fechaInicio}
              onChange={(e) => setFechaInicio(e.target.value)}
            />
          </div>
          <div className="form-group">
            <label>Fecha Fin</label>
            <input
              type="date"
              value={fechaFin}
              onChange={(e) => setFechaFin(e.target.value)}
            />
          </div>
          <div className="form-group" style={{ display: 'flex', alignItems: 'flex-end' }}>
            <button className="btn btn-primary" onClick={cargarReportes}>
              Buscar
            </button>
          </div>
        </div>

        {loading ? (
          <div className="loading"><div className="spinner"></div></div>
        ) : (
          <>
            <div style={{ marginBottom: '20px', padding: '15px', background: '#f3f4f6', borderRadius: '8px' }}>
              <h3 style={{ marginBottom: '10px' }}>Resumen de Ingresos</h3>
              <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(150px, 1fr))', gap: '15px' }}>
                <div>
                  <p style={{ color: '#6b7280', fontSize: '14px' }}>Total Ingresos</p>
                  <h2 style={{ color: '#10b981', fontSize: '24px' }}>S/ {ingresos?.total || '0.00'}</h2>
                </div>
                <div>
                  <p style={{ color: '#6b7280', fontSize: '14px' }}>Cantidad de Pagos</p>
                  <h2 style={{ fontSize: '24px' }}>{ingresos?.cantidad || 0}</h2>
                </div>
              </div>
            </div>

            <div className="table-container">
              <table>
                <thead>
                  <tr>
                    <th>Fecha</th>
                    <th>Código</th>
                    <th>Estudiante</th>
                    <th>Curso</th>
                    <th>Monto</th>
                    <th>Método</th>
                  </tr>
                </thead>
                <tbody>
                  {ingresos?.pagos && ingresos.pagos.length > 0 ? (
                    ingresos.pagos.map((pago) => (
                      <tr key={pago.codigo}>
                        <td>{new Date(pago.fecha_pago).toLocaleDateString()}</td>
                        <td>{pago.codigo}</td>
                        <td>{pago.nombres} {pago.apellidos}</td>
                        <td>{pago.curso}</td>
                        <td>S/ {parseFloat(pago.monto).toFixed(2)}</td>
                        <td><span className="badge badge-info">{pago.metodo_pago}</span></td>
                      </tr>
                    ))
                  ) : (
                    <tr>
                      <td colSpan="6" style={{ textAlign: 'center', padding: '20px' }}>
                        No hay pagos en este período
                      </td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          </>
        )}
      </div>

      {/* Reporte de Morosidad */}
      <div className="card">
        <div className="card-header">
          <h2 className="card-title">
            <FaExclamationTriangle style={{ color: '#f59e0b', marginRight: '10px' }} />
            Reporte de Morosidad (Deudas Pendientes)
          </h2>
        </div>

        {loading ? (
          <div className="loading"><div className="spinner"></div></div>
        ) : (
          <>
            <div style={{ marginBottom: '20px', padding: '15px', background: '#fef3c7', borderRadius: '8px' }}>
              <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(150px, 1fr))', gap: '15px' }}>
                <div>
                  <p style={{ color: '#92400e', fontSize: '14px' }}>Total Morosos</p>
                  <h2 style={{ color: '#b45309', fontSize: '24px' }}>{morosidad?.totalMorosos || 0}</h2>
                </div>
                <div>
                  <p style={{ color: '#92400e', fontSize: '14px' }}>Deuda Total</p>
                  <h2 style={{ color: '#ef4444', fontSize: '24px' }}>S/ {morosidad?.totalDeuda || '0.00'}</h2>
                </div>
              </div>
            </div>

            <div className="table-container">
              <table>
                <thead>
                  <tr>
                    <th>Código</th>
                    <th>DNI</th>
                    <th>Estudiante</th>
                    <th>Curso</th>
                    <th>Teléfono</th>
                    <th>Monto Total</th>
                    <th>Pagado</th>
                    <th>Pendiente</th>
                  </tr>
                </thead>
                <tbody>
                  {morosidad?.morosos && morosidad.morosos.length > 0 ? (
                    morosidad.morosos.map((moroso) => (
                      <tr key={moroso.matricula_codigo}>
                        <td>{moroso.estudiante_codigo}</td>
                        <td>{moroso.dni}</td>
                        <td>{moroso.nombres} {moroso.apellidos}</td>
                        <td>{moroso.curso}</td>
                        <td>{moroso.telefono || moroso.telefono_apoderado || '-'}</td>
                        <td>S/ {parseFloat(moroso.monto_total).toFixed(2)}</td>
                        <td>S/ {parseFloat(moroso.monto_pagado).toFixed(2)}</td>
                        <td style={{ color: '#ef4444', fontWeight: 'bold' }}>
                          S/ {parseFloat(moroso.monto_pendiente).toFixed(2)}
                        </td>
                      </tr>
                    ))
                  ) : (
                    <tr>
                      <td colSpan="8" style={{ textAlign: 'center', padding: '20px' }}>
                        No hay estudiantes con deudas pendientes
                      </td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          </>
        )}
      </div>
    </div>
  );
};

export default Reportes;
